Convert the following offset-based pagination endpoint to cursor-based pagination. The existing code uses a PostgreSQL database via a query helper function.

Existing code (offset-based):
```javascript
// GET /api/posts?page=1&limit=20
async function getPosts(req, res) {
    const page = parseInt(req.query.page) || 1;
    const limit = parseInt(req.query.limit) || 20;
    const offset = (page - 1) * limit;

    const countResult = await db.query('SELECT COUNT(*) FROM posts WHERE published = true');
    const totalCount = parseInt(countResult.rows[0].count);

    const result = await db.query(
        'SELECT id, title, content, author_id, created_at FROM posts WHERE published = true ORDER BY created_at DESC, id DESC LIMIT $1 OFFSET $2',
        [limit, offset]
    );

    res.json({
        posts: result.rows,
        pagination: {
            page,
            limit,
            totalCount,
            totalPages: Math.ceil(totalCount / limit),
        }
    });
}
```

Requirements for the cursor-based version:
1. Replace OFFSET with a WHERE clause that uses a cursor. Do NOT use OFFSET anywhere.
2. Use a compound cursor based on (created_at, id) since the sort is by created_at DESC, id DESC.
3. Encode the cursor as a base64-encoded JSON string (opaque to the client).
4. API should be: `GET /api/posts?limit=20&after=<cursor>` — no `page` parameter.
5. Use the LIMIT N+1 trick: fetch `limit + 1` rows, and if you get `limit + 1` results, there are more pages (set hasMore=true and return only `limit` rows).
6. Response format:
   ```json
   {
       "posts": [...],
       "pagination": {
           "hasMore": true,
           "nextCursor": "base64encodedstring",
           "limit": 20
       }
   }
   ```
7. When no `after` cursor is provided, return the first page (no WHERE filter on cursor).
8. Handle invalid/malformed cursors gracefully (return 400 error).
9. Remove the COUNT query — it is not needed and is expensive on large tables.

Provide the complete converted function. Include helper functions for encoding/decoding cursors. Explain briefly why cursor-based pagination is superior for this use case.

grok.modelOutput:
**Converted cursor-based implementation:**

```javascript
// Helpers for opaque cursor encoding/decoding
function encodeCursor(createdAt, id) {
    const value = createdAt instanceof Date ? createdAt.toISOString() : createdAt;
    const payload = { created_at: value, id: Number(id) };
    return Buffer.from(JSON.stringify(payload)).toString('base64');
}

function decodeCursor(cursorStr) {
    if (!cursorStr || typeof cursorStr !== 'string') {
        return null;
    }
    try {
        const json = Buffer.from(cursorStr, 'base64').toString('utf8');
        const obj = JSON.parse(json);

        if (typeof obj.created_at !== 'string' || typeof obj.id === 'undefined') {
            return null;
        }

        const id = Number(obj.id);
        if (isNaN(id)) return null;

        const created_at = new Date(obj.created_at);
        if (isNaN(created_at.getTime())) return null;

        return { created_at, id };
    } catch (err) {
        return null;
    }
}

// GET /api/posts?limit=20&after=<cursor>
async function getPosts(req, res) {
    const limit = parseInt(req.query.limit, 10) || 20;
    const after = req.query.after;

    let cursor = null;
    if (after) {
        cursor = decodeCursor(after);
        if (!cursor) {
            return res.status(400).json({ error: 'Invalid or malformed cursor' });
        }
    }

    const fetchLimit = limit + 1;

    let queryText;
    let params;

    if (cursor) {
        // Compound key filter for (created_at DESC, id DESC)
        queryText = `
            SELECT id, title, content, author_id, created_at 
            FROM posts 
            WHERE published = true 
              AND (created_at < $1 OR (created_at = $1 AND id < $2))
            ORDER BY created_at DESC, id DESC 
            LIMIT $3
        `;
        params = [cursor.created_at, cursor.id, fetchLimit];
    } else {
        // First page - no cursor filter
        queryText = `
            SELECT id, title, content, author_id, created_at 
            FROM posts 
            WHERE published = true 
            ORDER BY created_at DESC, id DESC 
            LIMIT $1
        `;
        params = [fetchLimit];
    }

    const result = await db.query(queryText, params);
    const rows = result.rows;

    const hasMore = rows.length > limit;
    const posts = hasMore ? rows.slice(0, limit) : rows;

    let nextCursor = null;
    if (hasMore && posts.length > 0) {
        const last = posts[posts.length - 1];
        nextCursor = encodeCursor(last.created_at, last.id);
    }

    res.json({
        posts,
        pagination: {
            hasMore,
            nextCursor,
            limit,
        }
    });
}
```

**Why cursor-based pagination is superior here:**

- **Performance on large tables**: `OFFSET` forces the database to scan and discard `N` rows on every page. A cursor `WHERE` clause (using an index on `(created_at, id)`) jumps directly to the right position.
- **Consistency under concurrent writes**: New inserts/deletes between requests can cause duplicates or skipped rows with offset pagination. Cursor pagination is stable because it uses the actual sort-key values of the last seen row.
- **No expensive `COUNT(*)`**: The old implementation ran a full table count on every request. Cursor pagination only needs `LIMIT N+1` (cheap) and never needs a total count.
- **Better UX for feeds/infinite scroll**: The `after=<opaque-cursor>` model works naturally with "load more" buttons and doesn't expose internal page numbers that can become invalid.
- **Scalability**: Works efficiently even when there are millions of rows because it never re-scans earlier data.

The cursor is intentionally opaque (base64 JSON) so clients cannot tamper with it and the internal sort-key representation can evolve later without breaking the API contract.
